#include <iostream>
#include <vector>
#include <queue>
#include <set>
#include <unordered_set>
using namespace std;

const int MAXN = 2 * 100005;
int n, k;
int parent[MAXN];
vector<int> adj[MAXN];

void dfs(int u, int p) {
    parent[u] = p;
    for (int v : adj[u]) {
        if (v != p) dfs(v, u);
    }
}

bool bfs(const vector<int>& leaves, unordered_set<int>& covered, int start) {
    queue<int> q;
    q.push(start);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        if (covered.count(u)) continue;
        covered.insert(u);
        for (int v : adj[u]) {
            if (covered.count(v)) continue;
            if (leaves.count(v)) return true;
            q.push(v);
        }
    }
    return false;
}

int min_friends_to_catch_vlad(const vector<int>& friends, const vector<int>& leaves) {
    unordered_set<int> covered;
    for (int f : friends) {
        if (!bfs(leaves, covered, f)) return 1;
    }
    return -1;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        cin >> n >> k;
        for (int i = 1; i <= n; ++i) adj[i].clear();
        for (int i = 0; i < n - 1; ++i) {
            int u, v;
            cin >> u >> v;
            adj[u].push_back(v);
            adj[v].push_back(u);
        }

        vector<int> friends(k);
        for (int i = 0; i < k; ++i) cin >> friends[i];

        // Find all leaf nodes (degree 1 except room 1)
        vector<int> leaves;
        for (int i = 1; i <= n; ++i) {
            if (adj[i].size() == 1 && i != 1) leaves.push_back(i);
        }

        // Check if Vlad can win
        bool vlad_can_win = bfs(leaves, {}, 1);
        if (vlad_can_win) {
            cout << -1 << endl;
            continue;
        }

        // Find minimum number of friends to block Vlad
        int result = min_friends_to_catch_vlad(friends, leaves);
        cout << result << endl;
    }

    return 0;
}

