ll comp_col[MAXN];
ll timer = 1, cur = 1;
ll last[MAXN];
bool active[MAXN];
ll curMap[MAXN];
int preProc[MAXN/B+16][MAXN];

void dfs1(ll u, ll par) {
    vll th(cols[u].size()), th2(cols[u].size());
    comps[u].resize(cols[u].size());
    for (ll i = 0; i < (ll)cols[u].size(); i++) {
        ll c = cols[u][i];
        th[i] = last[c];
        th2[i] = comp_col[c];
        comp_col[c] = (last[c] == par ? comp_col[c] : timer++);
        comps[u][i] = comp_col[c];
        last[c] = u;
    }
    for (ll v : adj[u]) {
        if (v == par) continue;
        dfs1(v, u);
    }
    for (ll i = 0; i < (ll)cols[u].size(); i++) {
        ll c = cols[u][i];
        last[c] = th[i];
        comp_col[c] = th2[i];
    }
}

void solve() {
