#include <bits/stdc++.h>
using namespace std;

#define forn(i, n) for (int i = 0; i < int(n); ++i)
#define trav(a, x) for (auto& a : x)

const int MAX_K = 3e5;
const int MAX_N = 3e5;

vector<int> adj[MAX_N];
int mask[MAX_N];

void dfs(int u, int p, const vector<vector<int>>& colors) {
    mask[u] = 0;
    for (int x : colors[u])
        mask[u] |= 1 << x;

    for (int v : adj[u]) {
        if (v == p) continue;
        dfs(v, u, colors);
        mask[u] &= mask[v];
    }
}

vector<int> solve(const vector<pair<int,int>>& edges,
                   const vector<vector<int>>& colors,
                   const vector<pair<int,int>>& queries) {
    int n = (int)adj[0].size();
    forn(u, n) adj[u].clear();
    forn(e, n - 1) {
        auto [u,v] = edges[e];
        --u, --v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    forn(u, n) mask[u] = 0;

    dfs(0, -1, colors);

    vector<int> ans;
    for (auto [u,v] : queries) {
        --u, --v;
        ans.push_back(__builtin_popcount(mask[u] & mask[v]));
    }

    return ans;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        int n, k, s, q;
        cin >> n >> k >> s >> q;

        vector<pair<int,int>> edges(n - 1);
        vector<vector<int>> colors(n + 1);
        forn(i, n - 1) {
            auto [u, v] = edges[i];
            cin >> u >> v;
        }

        forn(i, s) {
            int v, x;
            cin >> v >> x;
            --v;
            colors[v].push_back(x);
        }

        vector<pair<int,int>> queries(q);
        forn(i, q) {
            auto [u, v] = queries[i];
            cin >> u >> v;
        }

        auto ans = solve(edges, colors, queries);
        for (int x : ans)
            cout << x << " ";
        cout << "\n";
    }

    return 0;
}

