using namespace std;

const int MAXN = 2e5 + 5;
int n, m, q, dsu[MAXN], edge_weights[MAXN];
pair<int, pair<int, int>> edges[MAXN];

struct DSU {
    vector<int> parent, rank;
    DSU(int size) : parent(size), rank(size, 1) {
        iota(parent.begin(), parent.end(), 0);
    }
    int find(int x) {
        return parent[x] == x ? x : parent[x] = find(parent[x]);
    }
    void unite(int x, int y) {
        x = find(x); y = find(y);
        if (x != y) {
            if (rank[x] > rank[y]) swap(x, y);
            parent[x] = y;
            if (rank[x] == rank[y]) ++rank[y];
        }
    }
};

void addEdge(DSU &dsu, int u, int v, int w, bool &changed) {
    u = dsu.find(u); v = dsu.find(v);
    if (u == v) return;
    dsu.unite(u, v);
    changed = true;
}

void removeEdge(DSU &dsu, int u, int v, bool &changed) {
    u = dsu.find(u); v = dsu.find(v);
    if (u != v) return;
    dsu.parent[u] = u;
    changed = true;
}

int getCost(vector<pair<int, pair<int, int>>> &selected_edges) {
    int cost = 0;
    for (auto &p : selected_edges) {
        cost += p.first;
    }
    return cost;
}

int main() {
    ios::sync_with_stdio(false); cin.tie(nullptr);

    cin >> n >> m >> q;
    for (int i = 0; i < m; ++i) {
        cin >> edges[i].second.first >> edges[i].second.second >> edges[i].first;
        edge_weights[i] = edges[i].first;
    }

    sort(edges, edges + m);

    DSU dsu(n);
    vector<pair<int, pair<int, int>>> selected_edges;
    for (int i = 0; i < m && selected_edges.size() < n - 1; ++i) {
        auto &[w, uv] = edges[i];
        int u = uv.first - 1, v = uv.second - 1;
        if (dsu.find(u) != dsu.find(v)) {
            selected_edges.emplace_back(w, uv);
            dsu.unite(u, v);
        }
    }

    while (q--) {
        string op; int v;
        cin >> op >> v;
        --v;
        if (op == "+") {
            bool changed = false;
            for (int u = 0; u < n; ++u) {
                if (u != v) {
                    addEdge(dsu, u, v, edge_weights[(u * n + v)], changed);
                    if (changed) break;
                }
            }
        } else {
            bool changed = false;
            for (int u = 0; u < n; ++u) {
                if (u != v) {
                    removeEdge(dsu, u, v, changed);
                    if (changed) break;
                }
            }
        }
        cout << getCost(selected_edges) << '\n';
    }

    return 0;
}

