    for (int i = 0; i < n; ++i) {
        cin >> arr[i];
    }

    int odd_count = count_if(arr.begin(), arr.end(), [](int x) { return x % 2 != 0; });
    int even_count = n - odd_count;

    // Check feasibility
    if (p > even_count || (k - p) > odd_count) {
        cout << "NO" << endl;
        return;
    }

    // Create p parts with even sums using even numbers
    vector<vector<int>> parts(k);
    int even_index = 0;
    for (int i = 0; i < p; ++i) {
        parts[i].push_back(2); // Start with a known even number
        while (parts[i].back() * 2 <= arr[even_index]) {
            parts[i].back() *= 2;
        }
        parts[i].push_back(arr[even_index]);
        even_index++;
    }

    // Create k-p parts with odd sums using odd numbers
    int odd_index = 0;
    for (int i = p; i < k; ++i) {
        parts[i].push_back(1); // Start with a known odd number
        while (parts[i].back() * 2 <= arr[odd_index]) {
            parts[i].back() *= 2;
        }
        parts[i].push_back(arr[odd_index]);
        odd_index++;
    }

    // Distribute leftover even numbers among existing even-sum parts
    while (even_index < n) {
        for (int i = 0; i < p && even_index < n; ++i) {
            parts[i].push_back(arr[even_index]);
            even_index++;
