void dfs(int u, int parent, vector<pair<int, int>>& euler) {
    visited[u] = true;
    euler.push_back({u, -1});
    for (int v : adj[u]) {
        if (v == parent || !visited[v]) continue;
        dfs(v, u, euler);
        euler.push_back({u, v});
    }
}

bool isPassable(const vector<int>& querySet, const vector<pair<int, int>>& euler) {
    unordered_set<int> s(querySet.begin(), querySet.end());
    int start = querySet.front();
    bool foundStart = false;

    for (const auto& e : euler) {
        if (e.first == start && !foundStart) {
            foundStart = true;
            continue;
        }
        if (!s.count(e.first)) continue;
        if (foundStart) {
            if (!s.count(e.second)) return false;
            s.erase(e.first);
            s.erase(e.second);
        } else {
            if (s.count(e.second)) {
                start = e.second;
                foundStart = true;
            }
        }
    }
    return s.empty();
}

int main() {
    ios::sync_with_stdio(false); cin.tie(0);

    int n;
    cin >> n;
    for (int i = 0; i < n - 1; ++i) {
        int u, v;
