using namespace std;

int min_operations(int n, int k, vector<pair<int, int>>& rectangles) {
    set<int> rows, cols;

    for (const auto& rect : rectangles) {
        rows.insert(rect.first);
        cols.insert(rect.second);
    }

    int total_unique = rows.size() + cols.size();

    if (total_unique < k) {
        return -1;
    } else {
        // We need to cover at least k rows or columns
        // The minimum operations required will be max(k, total_unique)
        // because covering more than k rows/columns won't help if k rows/columns already covered
        return max(k, total_unique);
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
