#include <bits/stdc++.h>
using namespace std;

const int MAX_N = 2 * 100000 + 1;
int n, w;
vector<int> p(MAX_N);
vector<vector<int>> adj(MAX_N);

void dfs(int u, int par, vector<int>& num, vector<int>& depth, vector<int>& sz) {
    num[u] = ++sz[0];
    depth[u] = depth[par] + 1;
    for (int v : adj[u]) {
        if (v != par) {
            dfs(v, u, num, depth, sz);
        }
    }
}

void build(vector<int>& seg, int idx, int l, int r) {
    if (l == r) {
        seg[idx] = 0;
    } else {
        int mid = (l + r) / 2;
        build(seg, 2*idx, l, mid);
        build(seg, 2*idx+1, mid+1, r);
        seg[idx] = seg[2*idx] + seg[2*idx+1];
    }
}

void update(vector<int>& seg, int idx, int l, int r, int pos, int val) {
    if (l == r) {
        seg[idx] += val;
    } else {
        int mid = (l + r) / 2;
        if (pos <= mid) {
            update(seg, 2*idx, l, mid, pos, val);
        } else {
            update(seg, 2*idx+1, mid+1, r, pos, val);
        }
        seg[idx] = seg[2*idx] + seg[2*idx+1];
    }
}

int query(vector<int>& seg, int idx, int l, int r, int ql, int qr) {
    if (ql > r || qr < l) return 0;
    if (ql <= l && r <= qr) return seg[idx];
    int mid = (l + r) / 2;
    return query(seg, 2*idx, l, mid, ql, qr) + query(seg, 2*idx+1, mid+1, r, ql, qr);
}

long long calc_dist(int u, int mod, const vector<int>& num, const vector<int>& depth, const vector<int>& seg) {
    int target = (num[u] + mod) % (n + 1);
    int l = min(num[u], target);
    int r = max(num[u], target);
    int dist = depth[u] + depth[target] - 2 * depth[lca(u, target)];
    return dist + query(seg, 1, 1, n, l, r);
}

int lca(int u, int v) {
    while (true) {
        if (depth[u] > depth[v]) swap(u, v);
        v = p[v];
    }
}

vector<long long> solve(const vector<int>& p, const vector<int>& events) {
    vector<int> num(n + 1), depth(n + 1), sz(1, 0);
    vector<int> seg(4 * n);
    dfs(1, 0, num, depth, sz);

    for (int i = 2; i <= n; ++i) {
        adj[p[i]].push_back(i);
    }

    build(seg, 1, 1, n);

    vector<long long> ans(events.size());
    long long sum = 0;
    for (size_t i = 0; i < events.size(); ++i) {
        int x = events[i].first;
        int y = events[i].second;

        // Update weight
        update(seg, 1, 1, n, num[x], y);

        // Calculate new distances
        for (int j = 1; j <= n; ++j) {
            long long d = calc_dist(j, j % (n + 1), num, depth, seg);
            sum += d;
        }

        ans[i] = sum;
    }

    return ans;
}

