using namespace std;

int maxArea(int R, int G, int B, vector<int>& red, vector<int>& green, vector<int>& blue) {
    // Sort lengths to facilitate pairing
    sort(red.begin(), red.end());
    sort(green.begin(), green.end());
    sort(blue.begin(), blue.end());

    // Initialize DP table with -1 (impossible)
    vector<vector<vector<int>>> dp(R+1, vector<vector<int>>(G+1, vector<int>(B+1, -1)));
    dp[0][0][0] = 0;

    // Helper function to update DP table
    auto update = [&](int r, int g, int b, int area) {
        if (r >= 0 && g >= 0 && b >= 0 && dp[r][g][b] == -1) {
            dp[r][g][b] = area;
        } else if (r >= 0 && g >= 0 && b >= 0 && dp[r][g][b] < area) {
            dp[r][g][b] = area;
        }
    };

    // Fill DP table
    for (int r = 0; r <= R; ++r) {
        for (int g = 0; g <= G; ++g) {
            for (int b = 0; b <= B; ++b) {
                if (dp[r][g][b] != -1) {
                    if (r > 0) {
                        update(r-1, g, b, dp[r][g][b]);
                    }
                    if (g > 0) {
                        update(r, g-1, b, dp[r][g][b]);
                    }
                    if (b > 0) {
                        update(r, g, b-1, dp[r][g][b]);
                    }
                    if (r > 0 && g > 0) {
                        update(r-1, g-1, b, dp[r][g][b] + red[r-1] * green[g-1]);
                    }
                    if (r > 0 && b > 0) {
                        update(r-1, g, b-1, dp[r][g][b] + red[r-1] * blue[b-1]);
                    }
                    if (g > 0 && b > 0) {
                        update(r, g-1, b-1, dp[r][g][b] + green[g-1] * blue[b-1]);
                    }
                }
            }
        }
    }

    return dp[R][G][B];
}

