    for (int i = 0; i < n; ++i) {
        int d;
        cin >> d;
        cnt[d]++;
        sum += d;
    }

    // Check divisibility by 3
    int mod3 = sum % 3;
    if (mod3 == 1) {
        for (int d = 1; d <= 9; ++d) {
            if (d % 3 == 1 && cnt[d] > 0) {
                --cnt[d];
                break;
            }
        }
    } else if (mod3 == 2) {
        for (int d = 1; d <= 9; ++d) {
            if (d % 3 == 2 && cnt[d] > 0) {
                --cnt[d];
                break;
            }
        }
    }

    // Form the largest number
    bool found = false;
    string ans = "";
    for (int d = 9; d >= 0; --d) {
        if (cnt[d] > 0) {
            if (!found && (d % 2 != 0 || d == 0)) continue;
            ans.append(cnt[d], '0' + d);
            found = true;
        }
    }

    if (ans.empty()) cout << "-1\n";
    else cout << ans << '\n';

    return 0;
