int minCost(int n, vector<int>& a, vector<string>& f) {
    int dp[n + 1];
    fill(dp, dp + n + 1, INT_MAX);
    dp[n] = 0;

    for (int k = 4; k >= 1; --k) {
        vector<vector<int>> cost(n, vector<int>(n, 0));
        for (int i = 0; i <= n - k; ++i) {
            for (int j = 0; j <= n - k; ++j) {
                int cnt = 0;
                for (int x = i; x < i + k; ++x) {
                    for (int y = j; y < j + k; ++y) {
                        if (f[x][y] == '*') ++cnt;
                    }
                }
                cost[i][j] = a[k - 1] * cnt;
            }
        }

        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                if (i + k - 1 < n && j + k - 1 < n) {
                    dp[i] = min(dp[i], cost[i][j] + dp[j + k]);
                } else {
                    dp[i] = min(dp[i], cost[i][j]);
                }
            }
        }
    }

    return dp[0];
}

