    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> a(4);
    for (int& x : a) cin >> x;
    vector<string> f(4);
    for (string& s : f) cin >> s;

    cout << minCost(n, a, f) << '\n';

    return 0;
}

