int countWhiteLines(const vector<vector<char>>& grid) {
    int n = grid.size();
    int whiteRows = 0;
    int whiteCols = 0;

    // Check rows
    for (int i = 0; i < n; ++i) {
        bool allWhite = true;
        for (int j = 0; j < n; ++j) {
            if (grid[i][j] == 'B') {
                allWhite = false;
                break;
            }
        }
        if (allWhite) ++whiteRows;
    }

    // Check columns
    for (int j = 0; j < n; ++j) {
        bool allWhite = true;
        for (int i = 0; i < n; ++i) {
            if (grid[i][j] == 'B') {
                allWhite = false;
                break;
            }
        }
        if (allWhite) ++whiteCols;
    }

    return whiteRows + whiteCols;
}

void applyEraser(vector<vector<char>>& grid, int i, int j, int k) {
    for (int x = i; x < i + k; ++x) {
        for (int y = j; y < j + k; ++y) {
            grid[x][y] = 'W';
        }
    }
}

int solve(int n, int k, const vector<string>& gridStr) {
    vector<vector<char>> grid(n, vector<char>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            grid[i][j] = gridStr[i][j];
        }
    }

    int maxWhiteLines = 0;

    for (int i = 0; i <= n - k; ++i) {
        for (int j = 0; j <= n - k; ++j) {
            vector<vector<char>> tempGrid(grid);
            applyEraser(tempGrid, i, j, k);
            int whiteLines = countWhiteLines(tempGrid);
            maxWhiteLines = max(maxWhiteLines, whiteLines);
        }
    }

    return maxWhiteLines;
}

