int dist[MAXN];

void bfs(int start, int target, int& maxPathLen) {
    queue<int> q;
    fill(visited, visited + MAXN, false);
    fill(dist, dist + MAXN, INT_MAX);

    q.push(start);
    dist[start] = 0;
    visited[start] = true;

    while (!q.empty()) {
        int u = q.front();
        q.pop();

        for (int v : adj[u]) {
            if (!visited[v]) {
                visited[v] = true;
                dist[v] = dist[u] + 1;

                if (v == target) {
                    maxPathLen = dist[v];
                    return;
                }

                q.push(v);
            }
        }
    }
}

void dijkstra(int start, vector<pair<int, int>>& distances) {
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    fill(dist, dist + MAXN, INT_MAX);
    dist[start] = 0;
    pq.push({0, start});

    while (!pq.empty()) {
        auto [d, u] = pq.top(); pq.pop();

        if (d > dist[u]) continue;

        for (int v : adj[u]) {
            int alt = d + 1;

            if (alt < dist[v]) {
                dist[v] = alt;
                pq.push({alt, v});
            }
        }
    }
}

