    vector<long long> dp(m + 1, 0);
    dp[1] = 1;

    for (int j = 2; j <= m; ++j) {
        vector<long long> new_dp(m + 1, 0);
        for (int i = 1; i <= 3; ++i) {
            if (i == 1 && j > 1) { // Up-right move from (i, j-1)
