        if (segs[i].x1 > segs[i].x2) swap(segs[i].x1, segs[i].x2);
        if (segs[i].y1 > segs[i].y2) swap(segs[i].y1, segs[i].y2);
        xs.pb(segs[i].x1);
        xs.pb(segs[i].x2);
    }
    sort(all(xs));
    xs.erase(unique(all(xs)), xs.end());
    auto comp = [&](ll x) {
        return lower_bound(all(xs), x) - xs.begin();
    };

    vector<Segment> horiz, vert;
    for (auto& s : segs) {
        if (s.y1 == s.y2) horiz.pb(s);
        else vert.pb(s);
    }

    ll ans = 0;
    for (auto& h_low : horiz) {
        ll y_low = h_low.y1;
        ll xl = h_low.x1, xr = h_low.x2;
        vector<Event> events;
        for (auto& v : vert) {
            if (v.x1 >= xl && v.x1 <= xr && v.y1 <= y_low) {
                events.pb({v.y2, 1, v.x1, v.x1});
                events.pb({v.y1, -1, v.x1, v.x1});
