/*
 * Helper: BFS-based coloring of items.
 * The original algorithm:
 *   - pick a source node with the largest number of items
 *   - BFS from that source
 *   - for each node, assign smallest unused positive colors to its uncolored items
 *   - after BFS, any still-uncolored item gets color 1
 *   - output max color and the color assignment
 */
void solve() {
    int n, m;
    cin >> n >> m;

    vector<vll> X(n);
    ll src = 0;
    for (ll u = 0; u < n; ++u) {
        ll k;
        cin >> k;
        X[u].reserve(k);
        for (ll i = 0; i < k; ++i) {
            ll c;
            cin >> c;
            X[u].pb(c - 1);
        }
        if (X[u].size() > X[src].size()) {
            src = u;
        }
    }

    vector<vll > E(n);
    for (ll i = 0; i < n - 1; ++i) {
        ll u, v;
        cin >> u >> v;
        --u; --v;
        E[u].pb(v);
        E[v].pb(u);
    }

    vll color(m, 0);
    vector<bool> vis(n, false);
    vector<bool> used(m + 1, false);

    deque<ll> q;
    q.pb(src);
    while (!q.empty()) {
        ll u = q.front();
        q.pop_front();
        vis[u] = true;

        for (ll x : X[u]) {
            used[color[x]] = true;
        }

        ll ptr = 1;
        for (ll x : X[u]) {
            if (color[x] == 0) {
                while (used[ptr]) {
                    ++ptr;
                }
                color[x] = ptr;
                ++ptr;
            }
        }

        for (ll x : X[u]) {
            used[color[x]] = false;
        }

        for (ll v : E[u]) {
            if (!vis[v]) {
                q.pb(v);
            }
        }
    }

    for (ll x = 0; x < m; ++x) {
        if (color[x] == 0) {
            color[x] = 1;
        }
    }

    ll max_color = MAX(color);
    cout << max_color << '\n';
    for (ll i = 0; i < m; ++i) {
        cout << color[i] << (i + 1 == m ? '\n' : ' ');
    }
}

