    x = findSet(x);
    y = findSet(y);
    if (x != y) {
        if (rank[x] > rank[y]) parent[y] = x;
        else if (rank[x] < rank[y]) parent[x] = y;
        else {
            parent[x] = y;
            rank[y]++;
        }
    }
}

