int solve(int n, int k, vector<int>& a) {
    // Sort the array
    sort(a.begin(), a.end());

    // Min-heap to store indices of elements that could be removed
    priority_queue<int, vector<int>, greater<int>> pq;
    for (int i = 0; i < k; ++i) {
        pq.push(i);
    }

    int ans = a[k / 2];
    int pos = k;

    while (pos + k <= n) {
        // Remove the smallest element in the current window
        int idx = pq.top();
        pq.pop();

        // Update the answer if the new median is larger
        int new_median = a[(pos + k - 1) / 2];
        if (new_median > ans) {
            ans = new_median;
        }

        // Add the next element to the window
        pq.push(pos + k);
        pos += k;
    }

    return ans;
}

