const ll llinf = 1e18 + 100;
const int maxn = 1e5 + 100;

struct Val {
    ll v;
    Val() : v(0) {}
    Val(ll x) : v(x) {}

    friend Val operator+(Val a, Val b) {
        return Val(a.v + b.v);
    }

    Val& operator+=(Val a) {
        return *this = *this + a;
    }
};

bool operator==(Val a, Val b) {
    return a.v == b.v;
}

bool operator!=(Val a, Val b) {
    return !(a == b);
}

struct Segtree {
    static Val calc(Val a, Val b) {
        return min(a.v, b.v);
    }

    Val q[4 * maxn], up[4 * maxn];
    int n;

    void build(int v, int l, int r, vll &who) {
        up[v] = 0;
        if (l == r) {
            q[v] = who[l];
            return;
        }
        int m = (l + r) / 2;
        build(2 * v, l, m, who);
        build(2 * v + 1, m + 1, r, who);
        q[v] = calc(q[2 * v], q[2 * v + 1]);
    }

    void build(int n_, vll &who) {
        n = n_;
        build(1, 0, n - 1, who);
    }

    void push(int v, int l, int r) {
        if (up[v] != Val(0)) {
            q[v] += up[v];
            if (l != r) {
                up[2 * v] += up[v];
                up[2 * v + 1] += up[v];
            }
            up[v] = 0;
        }
    }

    void update(int v, int tl, int tr, int l, int r, Val w) {
        push(v, tl, tr);
        if (l > r)
            return;
        if (tl == l && tr == r) {
            up[v] += w;
            push(v, tl, tr);
            return;
        }
        int m = (tl + tr) / 2;
        update(2 * v, tl, m, l, min(r, m), w);
        update(2 * v + 1, m + 1, tr, max(l, m + 1), r, w);
        q[v] = calc(q[2 * v], q[2 * v + 1]);
    }

    void update(int l, int r, ll w) {
        update(1, 0, n - 1, l, r, w);
    }

    Val get(int v, int tl, int tr, int l, int r) {
        push(v, tl, tr);
        if (l > r)
            return llinf;
        if (tl == l && tr == r)
            return q[v];
        int m = (tl + tr) / 2;
        return calc(get(2 * v, tl, m, l, min(r, m)),
                    get(2 * v + 1, m + 1, tr, max(l, m + 1), r));
    }

    Val get(int l, int r) {
        return get(1, 0, n - 1, l, r);
    }
};

void solve() {
    int n, k;
    cin >> n >> k;
    vector<int> a(n);
    for (int &i : a)
        cin >> i;
    vll dp(n + 1);
    vector<int> nxt(n), prev(n);
    {
        map<int, int> go;
        for (int i = n - 1; i >= 0; i--) {
            int x = a[i];
            if (!go.count(x))
                nxt[i] = n;
            else
                nxt[i] = go[x];
            go[x] = i;
        }
        go.clear();
        for (int i = 0; i < n; i++) {
            int x = a[i];
            if (!go.count(x))
                prev[i] = -1;
            else
                prev[i] = go[x];
            go[x] = i;
        }
    }
    for (int iter = 0; iter < k; iter++) {
        Segtree q;
        q.build(n + 1, dp);
        vll pd(n + 1);
        for (int i = 0; i <= n; i++) {
            pd[i] = q.get(0, i - 1).v;
            if (i < n) {
                if (prev[i] != -1) {
                    q.update(0, prev[i], (i - prev[i]));
                }
                if (nxt[i] != n) {
                    q.update(0, i, -(nxt[i] - i));
                }
            }
        }
        swap(dp, pd);
    }
    ll tot = 0;
    map<int, int> q;
    for (int i = 0; i < n; i++) {
        int x = a[i];
        if (q.find(x) != q.end()) {
            tot += i - q[x];
        }
        q[x] = i;
    }
    cout << tot + dp.back() << '\n';
}

