    for (int i = 1; i <= n; ++i) {
        cin >> a[i];
    }

    vector<vector<long long>> dp(n + 1, vector<long long>(k + 1, LLONG_MAX));
    dp[0][0] = 0;

    vector<int> last(n + 1, 0);
    vector<int> first(n + 1, n + 1);

    vector<long long> prefix_cost(n + 1, 0);
    vector<long long> cost(n + 1, 0);

    for (int i = 1; i <= n; ++i) {
        last[a[i]] = i;
        first[a[i]] = min(first[a[i]], i);
        cost[a[i]] += last[a[i]] - first[a[i]];
        prefix_cost[i] = prefix_cost[i - 1] + cost[a[i]];
    }

    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= k; ++j) {
            for (int b = 0; b < i; ++b) {
                dp[i][j] = min(dp[i][j], dp[b][j - 1] + prefix_cost[i] - prefix_cost[b]);
            }
        }
    }

    cout << dp[n][k] << endl;

    return 0;
}

