    int closeCount = 0;

    // Count the total number of ')' characters
    for (char c : S) {
        if (c == ')') closeCount++;
    }

    // Find the position of the last non-')' character
    int lastNonCloseIndex = n - 1;
    while (lastNonCloseIndex >= 0 && S[lastNonCloseIndex] == ')') {
