const int MAXN = 2 * 100000 + 10;
int n, a[MAXN], g[MAXN], h[MAXN];
long long S[MAXN], T[MAXN];

void solve() {
    cin >> n;
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    // Compute g(i): length of longest non-increasing prefix ending at a[i]
    g[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] <= a[i - 1]) {
            g[i] = g[i - 1] + 1;
        } else {
            g[i] = 1;
        }
    }

    // Compute h(i): length of longest non-decreasing suffix starting at a[i]
    h[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] <= a[i + 1]) {
            h[i] = h[i + 1] + 1;
        } else {
            h[i] = 1;
        }
    }

    // Compute S(i)
    S[0] = 0;
    for (int i = 1; i < n; ++i) {
        S[i] = S[i - 1];
        if (i > 0 && a[i - 1] < a[i]) {
            S[i]++;
        }
    }

    // Compute T(i)
    T[n - 1] = 0;
    for (int i = n - 2; i >= 0; --i) {
        T[i] = T[i + 1];
        if (a[i] < a[i + 1]) {
            T[i]++;
        }
    }

    // Find minimum penalty
    long long min_penalty = LLONG_MAX;
    for (int k = 0; k < n; ++k) {
        min_penalty = min(min_penalty, S[k] + T[k]);
    }

    cout << min_penalty << endl;
}

