double solve(vector<int>& E, int U) {
    int n = E.size();
    double max_eta = -1;

    for (int i = 0; i <= n - 3; ++i) {
        for (int k = i + 2; k <= n - 1 && E[k] - E[i] <= U; ++k) {
            // Find the largest j such that i < j < k and E[j] is minimized to maximize eta
            auto it = upper_bound(E.begin() + i + 1, E.begin() + k, E[i]);
            if (it != E.begin() + k) {
                --it;
                int j = it - E.begin();
