const int MAXN = 500005;
vector<int> adj[MAXN];
int height[MAXN], edgeCount[MAXN];

void dfs(int u, int p) {
    height[u] = 0;
    for (int v : adj[u]) {
        if (v == p) continue;
        dfs(v, u);
        height[u] = max(height[u], height[v]);
        edgeCount[u]++;
    }
    height[u] += 1; // Add the edge connecting u and p
}

double expectHeight(int u, int p, double parentExpect) {
    double totalProb = pow(0.5, edgeCount[u]);
    double subExpect = 0;
    for (int v : adj[u]) {
        if (v == p) continue;
        subExpect += expectHeight(v, u, 0); // Recursive call
    }
    double expect = parentExpect + totalProb * subExpect;
    return expect;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int q;
    cin >> q;
    int root = 1;
    height[root] = 0;

    while (q--) {
        int type, v;
        cin >> type >> v;
        if (type == 1) {
            adj[v].push_back(adj.size());
            adj.back().push_back(v);
            dfs(root, -1);
