const int MOD = 1e9 + 7;
const int MAX_N = 1e6;
vector<int> flower_powers, box_powers;

void fft(vector<int>& a, bool invert) {
    int n = a.size();
    for (int len = 2; len <= n; len <<= 1) {
        double ang = 2 * M_PI / len * (invert ? -1 : 1);
        complex<double> wlen(cos(ang), sin(ang));
        for (int i = 0; i < n; i += len) {
            complex<double> w(1);
            for (int j = 0; j < len / 2; ++j) {
                complex<double> u(a[i + j]);
                complex<double> v(a[i + j + len / 2] * w);
                a[i + j] = u + v;
                a[i + j + len / 2] = u - v;
                w *= wlen;
            }
        }
    }
    if (invert)
        for (auto& val : a)
            val /= n;
}

vector<int> convolve(const vector<int>& a, const vector<int>& b) {
    vector<int> fa(a.begin(), a.end()), fb(b.begin(), b.end());
    size_t s = 1;
    while (s < fa.size() || s < fb.size())
        s <<= 1;
    fa.resize(s); fb.resize(s);
    fft(fa, false); fft(fb, false);
    for (size_t i = 0; i < s; ++i)
        fa[i] *= fb[i];
    fft(fa, true);
    return vector<int>(fa.begin(), fa.end());
}

int main() {
    ios::sync_with_stdio(false); cin.tie(nullptr);

    int F, B, N;
    cin >> F >> B >> N;

    flower_powers.assign(F, 1);
    for (int f = 0; f < F; ++f) {
        int p;
        cin >> p;
        flower_powers.push_back(p);
    }

    box_powers.assign(B, 1);
    for (int b = 0; b < B; ++b) {
        int c;
        cin >> c;
        box_powers.push_back(c);
    }

    auto flower_gen = convolve(flower_powers, flower_powers);
    auto box_gen = convolve(box_powers, box_powers);

    int result = 0;
    for (int i = 0; i < flower_gen.size(); ++i) {
        if (i >= N)
            break;
        long long coeff = flower_gen[i] * box_gen[N - i];
        result = (result + coeff % MOD) % MOD;
    }

    cout << result << endl;

    return 0;
}

