void solve() {
    int n;
    cin >> n;
    vector<int> a(n), b(n);
    for (int i = 0; i < n; ++i) cin >> a[i];
    for (int i = 0; i < n; ++i) cin >> b[i];

    // Initial match count
    int init_matches = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == b[i]) ++init_matches;
    }

    // Prefix and suffix match counts
    vector<int> pref_a(n, 0), suff_a(n, 0);
    vector<int> pref_b(n, 0), suff_b(n, 0);

    for (int i = 1; i < n; ++i) {
        if (a[i] == b[i-1]) pref_a[i] = pref_a[i-1] + 1;
        else pref_a[i] = pref_a[i-1];
        if (b[i] == a[i-1]) pref_b[i] = pref_b[i-1] + 1;
        else pref_b[i] = pref_b[i-1];
    }

    for (int i = n-2; i >= 0; --i) {
        if (a[i] == b[i+1]) suff_a[i] = suff_a[i+1] + 1;
        else suff_a[i] = suff_a[i+1];
        if (b[i] == a[i+1]) suff_b[i] = suff_b[i+1] + 1;
        else suff_b[i] = suff_b[i+1];
    }

    // Try removing each element and combining prefix/suffix
    int max_matches = init_matches;
    for (int i = 0; i < n; ++i) {
        int matches = pref_a[i] + suff_a[i] + pref_b[i] + suff_b[i];
        if (matches > max_matches) max_matches = matches;
    }

    cout << max_matches << '\n';
}

