ll find(vll& par, ll x) {
    return par[x] == x ? x : par[x] = find(par, par[x]);
}

bool unite(vll& par, ll a, ll b) {
    a = find(par, a);
    b = find(par, b);
    if (a == b) return false;
    par[a] = b;
    return true;
