void build_components() {
    int c = 0;
    rep(i, 1, 100010) {
        if (!adj[i].empty()) {
            comps.emplace_back();
            comp_bounds.emplace_back(-1, -1);
            dfs(i, -1, c++);
        }
    }
    rep(c, 0, sz(comps)) {
        auto &comp = comps[c];
        int min_val = *min_element(comp.begin(), comp.end());
        int max_val = *max_element(comp.begin(), comp.end());
        comp_bounds[c] = {min_val, max_val};
    }
}

bool overlaps(pii a, pii b) {
    return !(a.second < b.first || b.second < a.first);
}

ll min_feedings(int l, int r) {
    int cnt = 0;
    bool full_range = false;

    if (l == 1 && r == 100009) {
        full_range = true;
    } else if (l == 1) {
        while (!comps.empty() && comp_bounds.back().second >= r) {
            comps.pop_back();
            comp_bounds.pop_back();
        }
        cnt += (int)comps.size();
    } else if (r == 100009) {
        while (!comps.empty() && comp_bounds.front().first <= l) {
            comps.erase(comps.begin());
            comp_bounds.erase(comp_bounds.begin());
        }
        cnt += (int)comps.size();
    } else {
        while (!comps.empty() && comp_bounds.back().second >= r) {
            comps.pop_back();
            comp_bounds.pop_back();
        }

        while (!comps.empty() && comp_bounds.front().first <= l) {
            comps.erase(comps.begin());
            comp_bounds.erase(comp_bounds.begin());
        }

        cnt += (int)comps.size();
    }

    if (full_range) {
        return min(cnt, (int)comps.size());
    } else {
        vector<pair<int, int>> dp(100010, {INT_MAX, INT_MAX});
        dp[l] = {1, -1};

        for (int i = l; i <= r; ++i) {
            if (i > 1 && dp[i - 1].first != INT_MAX)
                dp[i] = {min(dp[i].first, dp[i - 1].first + 1), i - 1};

            int c = 0;
            for (; c < sz(comps); ++c) {
                if (overlaps(comp_bounds[c], {i, r})) break;
