#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

const int MOD = 998244353;

int solve(int n, int k, int len, vector<int>& arr) {
    // Initialize dp table
    vector<vector<long long>> dp(len + 1, vector<long long>(k + 1, 0));

    // Base case: first 'len' elements
    for (int i = 1; i <= len; ++i) {
        for (int val = 1; val <= k; ++val) {
            if (arr[i - 1] == -1 || arr[i - 1] == val) {
                dp[i][val] = 1;
            }
        }
    }

    // Slide the window
    for (int i = len; i < n; ++i) {
        for (int val = 1; val <= k; ++val) {
            dp[i % (len + 1)][val] = 0;
            for (int j = 1; j <= len; ++j) {
                if (arr[i - j + 1] == -1 || arr[i - j + 1] != val) {
                    dp[i % (len + 1)][val] = (dp[i % (len + 1)][val] + dp[(i - j) % (len + 1)][arr[i - j + 1]]) % MOD;
                }
            }
        }
    }

    // Sum up all valid configurations for the full length
    long long ans = 0;
    for (int val = 1; val <= k; ++val) {
        ans = (ans + dp[(n - 1) % (len + 1)][val]) % MOD;
    }

    return ans;
}

