    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, k, len;
    cin >> n >> k >> len;
    vector<int> arr(n);
    for (int i = 0; i < n; ++i) {
        cin >> arr[i];
    }

    cout << solve(n, k, len, arr) << '\n';

    return 0;
}

