int maxCleanRows(int n, vector<string>& rows) {
    int clean_rows = 0;
    for (const auto& row : rows) {
        bool all_ones = true;
        for (char c : row) {
            if (c == '0') {
                all_ones = false;
                break;
            }
        }
        if (all_ones) {
            clean_rows++;
        }
    }

    vector<int> improvements(n, 0);
    for (int j = 0; j < n; ++j) {
        int new_clean_rows = clean_rows;
        for (int i = 0; i < n; ++i) {
            if (rows[i][j] == '0') {
                rows[i][j] = '1';
                new_clean_rows += 1;
            } else {
                rows[i][j] = '0';
                new_clean_rows -= 1;
            }
        }
        improvements[j] = new_clean_rows - clean_rows;
        // Revert the change to keep the original matrix
        for (int i = 0; i < n; ++i) {
            if (rows[i][j] == '1') {
                rows[i][j] = '0';
            } else {
                rows[i][j] = '1';
            }
        }
    }

    sort(improvements.begin(), improvements.end());
    reverse(improvements.begin(), improvements.end());

    return min(clean_rows + improvements[0], n);
}

