    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<string> rows(n);
    for (int i = 0; i < n; ++i) {
        cin >> rows[i];
    }

    cout << maxCleanRows(n, rows) << endl;

