#include <iostream>
#include <vector>
#include <algorithm>
#include <iomanip>

using namespace std;

double solve(int n, double C, double T, vector<pair<int, int>>& problems) {
    const double EPS = 1e-9;
    vector<double> dp(T + 1, -1e9);
    dp[0] = 0;

    for (int t = 1; t <= T; ++t) {
        for (const auto& [a, p] : problems) {
            double min_time = 1e9;
            for (int e = 0; ; ++e) {
                double skill = pow(0.9, e);
                double time_per_problem = a / skill;
                if (time_per_problem > t) break;
                double remaining_time = t - time_per_problem;
                int next_t = max(t, int(time_per_problem));
                min_time = min(min_time, time_per_problem + dp[next_t]);
            }
            if (min_time < 1e9) {
                dp[t] = max(dp[t], dp[t - min_time] + p);
            }
        }
    }

    return max_element(dp.begin(), dp.end(), [](double x, double y){ return fabs(x - y) < EPS ? x < y : x < y; })->second;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

