        ll temp = b % a;
        b = a;
        a = temp;
    }
    return b;
}

ll lcm(ll a, ll b) {
    return a / gcd(a, b) * b;
}

ll ceildiv(ll n, ll k) {
    ll t = n / k;
    if (n % k == 0) return t;
    return t + 1;
