#include <iostream>
#include <vector>
using namespace std;

void solve(int n, int x) {
    vector<int> p(n);

    // Place x at position n - x + 1
    p[n - x] = x;

    // Fill the rest of the permutation sequentially
    for (int i = 0; i < n; ++i) {
        if (i != n - x) {
            p[i] = i % (n - x);
        }
    }

    // Print the permutation
    for (int i = 0; i < n; ++i) {
        cout << p[i] << " ";
    }
    cout << endl;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;

    while (t--) {
        int n, x;
        cin >> n >> x;

        solve(n, x);
    }

    return 0;
}
